def get_adjacent_reds(shape_cells, red_cells):
    shape_set = set(shape_cells)
    red_set = set(red_cells)
    result = []
    for r, c in red_set:
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            if (r+dr, c+dc) in shape_set:
                result.append((r, c))
                break
    return result

