# Good - now color 3 is properly split into two components.
# Let me rewrite the solve function to use connected components.

def solve(grid):
    import numpy as np
    from itertools import combinations, permutations
    from collections import deque

    g = np.array(grid)
    H, W = g.shape

    # Extract shapes as connected components
    shape_cells_map = {}
    for r in range(H):
        for c in range(W):
            if g[r,c] != 0 and g[r,c] != 2:
                shape_cells_map[(r,c)] = int(g[r,c])

    visited = set()
    components = []  # list of (color, set_of_cells)
    for start in shape_cells_map:
        if start in visited:
            continue
        queue = deque([start])
        visited.add(start)
        comp_cells = set()
        color = shape_cells_map[start]
        while queue:
            r, c = queue.popleft()
            comp_cells.add((r, c))
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if (nr, nc) in shape_cells_map and (nr, nc) not in visited and shape_cells_map[(nr,nc)] == color:
                    visited.add((nr, nc))
                    queue.append((nr, nc))
        components.append((color, comp_cells))

    # Find the yellow (4) component - it's the anchor
    yellow_idx = None
    for i, (color, cells) in enumerate(components):
        if color == 4:
            yellow_idx = i
            break

    if yellow_idx is None:
        return grid

    # Extract red cells
    red_cells = set()
    for r in range(H):
        for c in range(W):
            if g[r,c] == 2:
                red_cells.add((r,c))

    # For each component, find its adjacent red connectors
    comp_connectors = []  # parallel to components
    for i, (color, cells) in enumerate(components):
        conns = []
        for rr, rc in red_cells:
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = rr+dr, rc+dc
                if (nr, nc) in cells:
                    direction = (rr-nr, rc-nc)
                    conns.append(((rr, rc), direction))
                    break  # each red connects to at most one cell in this component
        comp_connectors.append(conns)

    # BFS from yellow
    output = [[0]*W for _ in range(H)]

    # Place yellow
    for r, c in components[yellow_idx][1]:
        output[r][c] = 4
    for red_pos, direction in comp_connectors[yellow_idx]:
        r, c = red_pos
        output[r][c] = 2

    placed = {yellow_idx}

    # Active ports: list of (global_red_pos, direction)
    active_ports = [(red_pos, direction) for red_pos, direction in comp_connectors[yellow_idx]]

    def find_match_for_component(ports, comp_idx):
        conns = comp_connectors[comp_idx]
        if not conns or len(conns) == 0:
            return None

        for size in range(2, min(len(ports), len(conns)) + 1):
            for pidx in combinations(range(len(ports)), size):
                sub_ports = [ports[i] for i in pidx]
                for cidx in combinations(range(len(conns)), size):
                    sub_conns = [conns[i] for i in cidx]
                    for perm in permutations(range(size)):
                        dir_ok = all(
                            sub_ports[k][1] == (-sub_conns[perm[k]][1][0], -sub_conns[perm[k]][1][1])
                            for k in range(size)
                        )
                        if not dir_ok:
                            continue
                        translations = set()
                        for k in range(size):
                            dr = sub_ports[k][0][0] - sub_conns[perm[k]][0][0]
                            dc = sub_ports[k][0][1] - sub_conns[perm[k]][0][1]
                            translations.add((dr, dc))
                        if len(translations) == 1:
                            t = translations.pop()
                            matched_cidx = set(cidx[perm[k]] for k in range(size))
                            return (set(pidx), matched_cidx, t)
        return None

    max_iter = 20
    for _ in range(max_iter):
        if not active_ports:
            break

        found = False
        for comp_idx in range(len(components)):
            if comp_idx in placed:
                continue

            result = find_match_for_component(active_ports, comp_idx)
            if result:
                port_used, conn_used, (tr, tc) = result

                color, cells = components[comp_idx]

                # Place the shape
                for r, c in cells:
                    nr, nc = r + tr, c + tc
                    if 0 <= nr < H and 0 <= nc < W:
                        output[nr][nc] = color

                # Place all red connectors (both matched and unmatched)
                conns = comp_connectors[comp_idx]
                for i, (red_pos, direction) in enumerate(conns):
                    rr, rc = red_pos
                    nr, nc = rr + tr, rc + tc
                    if 0 <= nr < H and 0 <= nc < W:
                        output[nr][nc] = 2

                # Remove used ports
                active_ports = [p for i, p in enumerate(active_ports) if i not in port_used]

                # Add remaining connectors as new ports
                for i, (red_pos, direction) in enumerate(conns):
                    if i not in conn_used:
                        nr, nc = red_pos[0] + tr, red_pos[1] + tc
                        active_ports.append(((nr, nc), direction))

                placed.add(comp_idx)
                found = True
                break

        if not found:
            break

    return output

# Test
r0 = solve(train_samples[0]['input'])
r1 = solve(train_samples[1]['input'])
